ExternalServiceRegistration.schema:
{
  "openapi": "3.1.0",
  "info": {
    "title": "Free Currency API",
    "summary": "Retrieves Currency Data",
    "description": "Retrieve Currency Data from Free Currency API",
    "contact": {
      "name": "Free Currency API Support",
      "url": "https://freecurrencyapi.com/docs/#official-libraries",
      "email": "support@freecurrencyapi.com"
    },
    "version": "1.0.2"
  },
  "servers": [{
    "url": "https://api.freecurrencyapi.com/v1",
    "description": "Free Currency API Endpoint"
  }],
  "paths": {
    "/status": {
      "get": {
        "operationId": "fcaStatus",
        "tags": [
          "API Status"
        ],
        "summary": "Retrieves usage information and remaining requests",
        "externalDocs": {
          "description": "API Spec page",
          "url": "https://freecurrencyapi.com/docs/status#request-parameters"
        },
        "responses": {
          "200": {
            "description": "Successfull Response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "quotas": {
                      "type": "object",
                      "properties": {
                        "month": {
                          "type": "object",
                          "properties": {
                            "total": {
                              "type": "integer"
                            },
                            "used": {
                              "type": "integer"
                            },
                            "remaining": {
                              "type": "integer"
                            }
                          },
                          "examples": [{
                            "total": 300,
                            "used": 71,
                            "remaining": 229
                          }]
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/currencies": {
      "get": {
        "operationId": "fcaCurrencies",
        "tags": [
          "Currencies"
        ],
        "summary": "Returns all our supported currencies",
        "externalDocs": {
          "description": "API Spec page",
          "url": "https://freecurrencyapi.com/docs/currencies#request-parameters"
        },
        "parameters": [{
          "in": "query",
          "name": "currencies",
          "schema": {
            "type": "string"
          },
          "required": false,
          "description": "List of currency codes sepparated by comma"
        }],
        "responses": {
          "200": {
            "description": "Successfull Response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "data": {
                      "type": "object",
                      "additionalProperties": {
                        "properties": {
                          "symbol": {
                            "type": "string"
                          },
                          "name": {
                            "type": "string"
                          },
                          "symbol_native": {
                            "type": "string"
                          },
                          "decimal_digits": {
                            "type": "integer"
                          },
                          "rounding": {
                            "type": "integer"
                          },
                          "code": {
                            "type": "string"
                          },
                          "name_plural": {
                            "type": "string"
                          },
                          "type": {
                            "type": "string"
                          }
                        },
                        "examples": [{
                          "symbol": "$",
                          "name": "USD Dollar",
                          "symbol_native": "$",
                          "decimal_digits": 2,
                          "rounding": 0,
                          "code": "USD",
                          "name_plural": "US dollars",
                          "type": "fiat"
                        }],
                        "type": "object"
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/latest": {
      "get": {
        "operationId": "fcaLatest",
        "tags": [
          "Latest Currency Value"
        ],
        "summary": "Provides latest value for indicated currencies",
        "externalDocs": {
          "description": "API Spec page",
          "url": "https://freecurrencyapi.com/docs"
        },
        "parameters": [{
          "in": "query",
          "name": "currencies",
          "schema": {
            "type": "string"
          },
          "required": false,
          "description": "List of currency codes sepparated by comma"
        }],
        "responses": {
          "200": {
            "description": "Successfull Response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "data": {
                      "type": "object",
                      "additionalProperties": {
                        "type": "integer"
                      },
                      "examples": [{
                        "EUR": 0.8764201365
                      }]
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "CurrencyData": {
        "type": "object",
        "properties": {
          "symbol": {
            "type": "string"
          },
          "name": {
            "type": "string"
          },
          "symbol_native": {
            "type": "string"
          },
          "decimal_digits": {
            "type": "integer"
          },
          "rounding": {
            "type": "integer"
          },
          "code": {
            "type": "string"
          },
          "name_plural": {
            "type": "string"
          },
          "type": {
            "type": "string"
          }
        },
        "examples": [{
          "symbol": "$",
          "name": "USD Dollar",
          "symbol_native": "$",
          "decimal_digits": 2,
          "rounding": 0,
          "code": "USD",
          "name_plural": "US dollars",
          "type": "fiat"
        }]
      }
    }
  }
}
